    handleRoute() {
        const isArticlePage = window.location.pathname.includes('article.html');
        let hash = window.location.hash.slice(1) || '/';
        if (hash.startsWith('/')) {
            hash = hash.slice(1);
        }
        const parts = hash.split('/');
        const route = parts[0];

        if (route === 'article' && parts[1]) {
            this.renderArticle(parts[1]);
        } else if (route === 'search' && parts[1]) {
            this.renderSearch(decodeURIComponent(parts[1]));
        } else if (isArticlePage) {
            // If on article page but no article slug, go back to home
            window.location.href = 'index.html#/';
        } else if (route === '' || route === 'page') {
            this.currentPage = route === 'page' ? parseInt(parts[1]) || 1 : 1;
            this.renderHome();
        } else if (route === 'category' && parts[1]) {
            this.currentPage = parts[2] ? parseInt(parts[2]) || 1 : 1;
            this.renderCategory(parts[1]);
        } else {
            this.currentPage = 1;
            this.renderHome();
        }
        
        // Scroll to top on every route change
        window.scrollTo(0, 0);
    }

    showLoading() {
        const app = document.getElementById('app');
        app.innerHTML = '<div class="loading">Loading...</div>';
    }

    renderModules(articleIndex) {
        const modulesContainer = document.getElementById('modules-container');
        const sidebarContainer = document.getElementById('sidebar-category-widgets');
        
        if (!modulesContainer || !siteConfig.design.modules || siteConfig.design.modules.length === 0) {
            return '';
        }

        let mainModulesHtml = '';
        let sidebarModulesHtml = '';
        const modules = siteConfig.design.modules;
        
        // Randomly decide which modules go to sidebar vs main content
        modules.forEach((moduleType, index) => {
            let html = '';
            if (moduleType === 'featured-section') {
                html = this.renderFeaturedSection(articleIndex);
            } else if (moduleType === 'category-highlights') {
                html = this.renderCategoryHighlights();
            } else if (moduleType === 'trending-articles') {
                html = this.renderTrendingArticles(articleIndex);
            } else if (moduleType === 'about-widget') {
                html = this.renderAboutWidget();
            } else if (moduleType === 'newsletter-signup') {
                html = this.renderNewsletterSignup();
            } else if (moduleType === 'recent-comments') {
                html = this.renderRecentComments();
            } else if (moduleType === 'stats-widget') {
                html = this.renderStatsWidget(articleIndex);
            } else if (moduleType === 'social-links') {
                html = this.renderSocialLinks();
            } else if (moduleType === 'popular-tags') {
                html = this.renderPopularTags();
            }

            // Heuristic: some modules are better in sidebar, others in main
            const sidebarFriendly = ['about-widget', 'recent-comments', 'social-links', 'popular-tags', 'trending-articles'];
            
            if (sidebarFriendly.includes(moduleType) && Math.random() > 0.3) {
                sidebarModulesHtml += html;
            } else {
                mainModulesHtml += html;
            }
        });
        
        if (modulesContainer) modulesContainer.innerHTML = mainModulesHtml;
        if (sidebarContainer) sidebarContainer.innerHTML = sidebarModulesHtml;
    }

